class Solution {
public:
    int binaryGap(int n) {
        int max_gap = 0;
        int last_pos = -1;
        int current_pos = 0;

        while (n > 0) {
            if (n & 1) {
                if (last_pos != -1) {
                    int gap = current_pos - last_pos;
                    if (gap > max_gap) {
                        max_gap = gap;
                    }
                } else {
                    last_pos = current_pos;
                }
            }
            n >>= 1;
            current_pos++;
        }

        return max_gap;
    }
};

